// AGENTE 2 - Normalização, deduplicação, pré-filtros, score heurístico e métricas
// Responsabilidades deste node: converter fontes diferentes para um contrato único,
// deduplicar por múltiplas chaves, calcular score barato antes da IA e registrar
// todo descarte com motivo. Ajuste CONFIG para calibrar volume/custo sem alterar o fluxo.

const CONFIG = {
  limiteScoreIA: Number($env.RADAR_VAGAS_SCORE_MINIMO_IA || 45),
  maxDescricao: 5000,
  tecnologiasPerfil: ['javascript', 'python', 'sql', 'postgresql', 'supabase', 'n8n', 'git', 'github', 'openai', 'claude', 'react', 'node'],
  localidadesBrasil: ['brasil', 'brazil', 'porto alegre', 'poa', 'rio grande do sul', 'rs', 'são paulo', 'sao paulo', 'rio de janeiro', 'florianópolis', 'florianopolis', 'curitiba', 'belo horizonte'],
  termosObrigatorios: ['intern', 'estágio', 'estagio', 'junior', 'júnior', 'jr', 'entry level', 'graduate', 'trainee', 'developer', 'engineer', 'desenvolvedor', 'desenvolvedora', 'programador'],
  areasExcluidas: ['devops', 'data engineer', 'engenheiro de dados', 'qa senior', 'quality assurance senior', 'architect', 'arquiteto', 'principal', 'lead', 'staff', 'manager', 'gerente']
};

const stripHtml = (value) => String(value || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const lower = (value) => stripHtml(value).toLowerCase();
const compact = (value) => lower(value).replace(/[^a-z0-9]+/g, ' ').trim();
const hash = (value) => {
  let h = 2166136261;
  const text = compact(value).slice(0, 2000);
  for (let i = 0; i < text.length; i++) { h ^= text.charCodeAt(i); h += (h << 1) + (h << 4) + (h << 7) + (h << 8) + (h << 24); }
  return (h >>> 0).toString(16);
};
const asArray = (v) => Array.isArray(v) ? v : (v ? [v] : []);
const unique = (arr) => [...new Set(arr.filter(Boolean).map(String))];
const hasAny = (text, terms) => terms.some(t => new RegExp(`(^|[^a-z0-9])${t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}([^a-z0-9]|$)`, 'i').test(text));

let idsExistentes = [];
try {
  const notionResp = $('Buscar Vagas já salvas no Notion').first().json;
  idsExistentes = (notionResp.results || []).map(page => page.properties?.['ID Externo']?.rich_text?.[0]?.plain_text || '').filter(Boolean);
} catch (e) { idsExistentes = []; }
const idsSalvos = new Set(idsExistentes);

function detectRemote(job, localText) {
  return Boolean(job.remote || job.is_remote || job.workplaceType === 'remote' || /remote|remoto|anywhere|worldwide/i.test(localText));
}
function detectSeniority(text) {
  if (/\b(intern|internship|estágio|estagio|trainee)\b/i.test(text)) return 'Estagio';
  if (/\b(junior|júnior|jr\.?|entry level|graduate)\b/i.test(text)) return 'Junior';
  if (/\b(senior|sr\.?)\b/i.test(text)) return 'Senior';
  if (/\b(staff|principal|lead|manager|architect)\b/i.test(text)) return 'Incompativel';
  return 'Nao especificado';
}
function detectTech(text, tags = []) {
  const bag = `${text} ${asArray(tags).join(' ')}`;
  const aliases = { javascript:['javascript','js'], python:['python'], sql:['sql'], postgresql:['postgres','postgresql'], supabase:['supabase'], n8n:['n8n'], git:['git'], github:['github'], openai:['openai','gpt'], claude:['claude'], react:['react'], node:['node','node.js','nodejs'] };
  return Object.entries(aliases).filter(([, names]) => hasAny(bag, names)).map(([tech]) => tech);
}
function normalize(job, source) {
  const titulo = job.position || job.title || job.jobTitle || job.name || 'Título não informado';
  const empresa = job.company || job.company_name || job.companyName || job.organization || 'Não informado';
  const local = job.location || job.candidate_required_location || job.jobLocation || job.city || 'Não informado';
  const descricao = stripHtml(job.description || job.jobDescription || job.summary || job.text).slice(0, CONFIG.maxDescricao);
  const url = job.url || job.applyUrl || job.link || job.jobUrl || job.linkedinUrl || '';
  const tags = asArray(job.tags || job.keywords || job.skills);
  const text = `${titulo} ${empresa} ${local} ${descricao} ${tags.join(' ')}`;
  const idRaw = job.id || job.slug || job.jobId || job.externalId || url || `${empresa}-${titulo}-${hash(descricao)}`;
  const tecnologias = detectTech(text, tags);
  return {
    id: `${source.toLowerCase()}_${idRaw}`,
    id_externo: `${source.toLowerCase()}_${idRaw}`,
    titulo, empresa, descricao, url, link: url, fonte: source, local,
    remoto: detectRemote(job, local),
    senioridade: detectSeniority(text),
    tecnologias,
    tags: unique([...tags, ...tecnologias]),
    salario: job.salary || job.salaryText || job.compensation || null,
    tipo_contrato: job.jobType || job.contractType || job.employmentType || null,
    idioma: /\benglish|required english|ingl[eê]s\b/i.test(text) ? 'Inglês' : (/\bportugu[eê]s|portuguese\b/i.test(text) ? 'Português' : 'Não especificado'),
    data_publicacao: job.date || job.publication_date || job.published_at || job.created_at || job.postedAt || null,
    hash_descricao: hash(descricao)
  };
}
function score(v) {
  const text = lower(`${v.titulo} ${v.descricao} ${v.local} ${v.tecnologias.join(' ')}`);
  let pontos = 0, motivos = [];
  const add = (n,m) => { pontos += n; motivos.push(`${n > 0 ? '+' : ''}${n} ${m}`); };
  if (/estágio|estagio/.test(text)) add(25, 'estágio');
  if (/junior|júnior|jr\.?|entry level/.test(text)) add(20, 'júnior/entry level');
  if (/intern|internship/.test(text)) add(15, 'intern');
  if (v.remoto) add(10, 'remoto');
  if (/brasil|brazil/.test(text)) add(10, 'Brasil');
  if (/porto alegre|\bpoa\b/.test(text)) add(10, 'Porto Alegre');
  for (const tech of ['javascript','python','react','node','postgresql','n8n','openai']) if (v.tecnologias.includes(tech)) add(10, tech);
  for (const [term, penalty] of [['senior',-40],['staff',-50],['principal',-50],['lead',-50],['manager',-80]]) if (hasAny(text, [term])) add(penalty, term);
  return { pontos, motivos };
}
function discardReasons(v, pontos) {
  const text = lower(`${v.titulo} ${v.descricao} ${v.local}`);
  const reasons = [];
  if (hasAny(text, CONFIG.areasExcluidas)) reasons.push('Área/senioridade incompatível');
  if (!v.remoto && !hasAny(lower(v.local), CONFIG.localidadesBrasil)) reasons.push('Localização incompatível');
  if (!hasAny(text, CONFIG.termosObrigatorios) && v.tecnologias.length === 0) reasons.push('Tecnologia/área incompatível');
  if (pontos < CONFIG.limiteScoreIA) reasons.push(`Score heurístico muito baixo (${pontos} < ${CONFIG.limiteScoreIA})`);
  return unique(reasons);
}

const rawItems = $input.all();
const vagas = [];
for (const item of rawItems) {
  const body = item.json;
  if (Array.isArray(body)) for (const job of body) if (job && (job.id || job.position || job.title)) vagas.push(normalize(job, 'RemoteOK'));
  if (body?.jobs) for (const job of body.jobs) vagas.push(normalize(job, 'Remotive'));
  if (body?.data) for (const job of body.data) vagas.push(normalize(job, 'Arbeitnow'));
  if (body?.items) for (const job of body.items) vagas.push(normalize(job, item.json.source || 'Apify'));
  if (body?.title || body?.jobTitle) vagas.push(normalize(body, body.source || body.fonte || 'Apify'));
}

const seen = new Set();
const output = [];
for (const v of vagas) {
  const keys = [v.id_externo, v.url, `${compact(v.empresa)}|${compact(v.titulo)}`, v.hash_descricao].filter(Boolean);
  const duplicada = keys.some(k => seen.has(k) || idsSalvos.has(k));
  keys.forEach(k => seen.add(k));
  const { pontos, motivos } = score(v);
  const reasons = duplicada ? ['Duplicada'] : discardReasons(v, pontos);
  output.push({ json: { ...v, score_heuristico: pontos, motivo_score: motivos.join('; '), status_pipeline: reasons.length ? 'Descartada antes da IA' : 'Elegível para IA', motivo_descarte: reasons.join('; '), enviar_para_ia: reasons.length === 0, metricas: { limite_score_ia: CONFIG.limiteScoreIA } } });
}
console.log(`RadarVagas: ${vagas.length} normalizadas, ${output.filter(i=>i.json.enviar_para_ia).length} enviadas para IA, ${output.filter(i=>!i.json.enviar_para_ia).length} descartadas antes da IA.`);
return output;

