// Extrai o JSON retornado pela OpenAI (vem dentro de choices[0].message.content)
const resp = $input.first().json;
let texto = '';
try {
  texto = resp.choices[0].message.content;
} catch (e) {
  texto = '{}';
}

// Remove possíveis cercas de markdown, por segurança (response_format json_object já evita isso, mas não custa manter)
texto = texto.replace(/```json/g, '').replace(/```/g, '').trim();

let avaliacao;
try {
  avaliacao = JSON.parse(texto);
} catch (e) {
  avaliacao = {
    compatibilidade: 0,
    vale_a_pena: false, prioridade: 'Baixa', chance_entrevista: 0, motivo_score: 'Erro ao interpretar resposta da IA', gaps: ['Erro ao interpretar resposta da IA'], tecnologias_encontradas: [], tecnologias_faltantes: [], senioridade_detectada: 'Nao especificado', empresa_resumo: '', empresa_confiavel: false, ghost_job_probabilidade: 100, ingles_obrigatorio: false, anos_experiencia: null, curriculo_precisa_personalizacao: true, carta_apresentacao_recomendada: false
  };
}

const vaga = $('Processar Uma Vaga por Vez').item.json;

return [{
  json: {
    ...vaga,
    ...avaliacao,
    score_ia: Number(avaliacao.compatibilidade || 0),
    status_pipeline: avaliacao.vale_a_pena && Number(avaliacao.compatibilidade || 0) >= 75 ? 'Aprovada pela IA' : 'Descartada pela IA',
    motivo_descarte: avaliacao.vale_a_pena && Number(avaliacao.compatibilidade || 0) >= 75 ? '' : (avaliacao.motivo_score || 'IA incompatível')
  }
}];
